"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[1747],{182:(n,a,s)=>{s.r(a),s.d(a,{data:()=>e});const e={key:"v-324bb9aa",path:"/leetcode/offer/10-%20II.%20%E9%9D%92%E8%9B%99%E8%B7%B3%E5%8F%B0%E9%98%B6%E9%97%AE%E9%A2%98.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"II. 青蛙跳台阶问题",slug:"ii-青蛙跳台阶问题",children:[{level:3,title:"示例 1：",slug:"示例-1",children:[]},{level:3,title:"示例 2：",slug:"示例-2",children:[]},{level:3,title:"示例 3：",slug:"示例-3",children:[]}]},{level:2,title:"分析",slug:"分析",children:[{level:3,title:"代码",slug:"代码",children:[]}]}],filePathRelative:"leetcode/offer/10- II. 青蛙跳台阶问题.md",git:{updatedTime:1623368229e3,contributors:[{name:"atrist",email:"atristmu@outlook.com",commits:1}]}}},4214:(n,a,s)=>{s.r(a),s.d(a,{default:()=>t});const e=(0,s(6252).uE)('<h2 id="ii-青蛙跳台阶问题" tabindex="-1"><a class="header-anchor" href="#ii-青蛙跳台阶问题" aria-hidden="true">#</a> II. 青蛙跳台阶问题</h2><p>一只青蛙一次可以跳上1级台阶，也可以跳上2级台阶。求该青蛙跳上一个 n 级的台阶总共有多少种跳法。</p><p>答案需要取模 1e9+7（1000000007），如计算初始结果为：1000000008，请返回 1。</p><h3 id="示例-1" tabindex="-1"><a class="header-anchor" href="#示例-1" aria-hidden="true">#</a> 示例 1：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：n = 2\n输出：2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="示例-2" tabindex="-1"><a class="header-anchor" href="#示例-2" aria-hidden="true">#</a> 示例 2：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：n = 7\n输出：21\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="示例-3" tabindex="-1"><a class="header-anchor" href="#示例-3" aria-hidden="true">#</a> 示例 3：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：n = 0\n输出：1\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="分析" tabindex="-1"><a class="header-anchor" href="#分析" aria-hidden="true">#</a> 分析</h2><p>设 dp(i) 为 跳上 i 台阶的跳法</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>dp(i) = dp(i-1) + dp(i-2)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><ul><li>dp(0) = 1</li><li>dp(1) = 1</li><li>dp(2) = 2</li></ul><p>这道题本质上跟菲波那数列是一样的，只是，初始值不同。</p><h3 id="代码" tabindex="-1"><a class="header-anchor" href="#代码" aria-hidden="true">#</a> 代码</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> <span class="token function-variable function">numWays</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">n</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">let</span> n1 <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">,</span>n2<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">,</span>sum<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">;</span>\n  <span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">let</span> i<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">;</span>i<span class="token operator">&lt;</span>n<span class="token punctuation">;</span>i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n    sum  <span class="token operator">=</span> <span class="token punctuation">(</span>n1<span class="token operator">+</span>n2<span class="token punctuation">)</span><span class="token operator">%</span><span class="token number">1000000007</span>\n    n1 <span class="token operator">=</span> n2\n    n2 <span class="token operator">=</span> sum\n  <span class="token punctuation">}</span>\n  <span class="token keyword">return</span> n1\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div>',16),t={render:function(n,a){return e}}}}]);